const item = items[0].json;

function getPath(obj, path) {
  return path.split('.').reduce((acc, key) => (acc == null ? undefined : acc[key]), obj);
}

// Só os campos "duros" — presença estável, mesmos exigidos pelo gate
// de bloqueio da petição. Nunca mudaram de endereço nos bugs que já vimos.
const camposCriticos = {
  data_admissao: { label: "Data de admissão", path: "vinculo.inicio" },
  data_saida:    { label: "Data de saída (ou 'ainda trabalha')", path: "vinculo.fim" },
  salario:       { label: "Salário", path: "vinculo.salario_medio" },
  tipo_rescisao: { label: "Tipo de rescisão", path: "rescisao.tipo" },
};

const schemaDocumentos = {
  ctps: "CTPS", trct: "TRCT", extrato_fgts: "Extrato do FGTS",
  contracheque: "Contracheques", prova_agravante: "Provas de agravante",
};

const dados = item.triagem || {};
const documentos = item.documentos || [];

const faltantesCriticos = [];
for (const [campo, info] of Object.entries(camposCriticos)) {
  const valor = getPath(dados, info.path);
  if (valor === undefined || valor === null || valor === "") {
    faltantesCriticos.push(`${campo}: ${info.label}`);
  }
}

const tiposRecebidos = new Set(documentos.map(d => d.tipo_documento).filter(Boolean));
const documentosRecebidos = [];
const documentosFaltantes = [];
for (const [tipo, label] of Object.entries(schemaDocumentos)) {
  (tiposRecebidos.has(tipo) ? documentosRecebidos : documentosFaltantes).push(label);
}

return [{
  json: {
    id: item.id,
    nome: item.cliente_nome_completo || item.nome,
    telefone: item.telefone,
    etapa: item.etapa,
    entrevista_pode_iniciar: item.area_juridica === "trabalhista" && ["fechado", "entrevista"].includes(item.etapa),

    // 🆕 dado bruto — o agente interpreta sozinho o que já foi dito
    triagem_bruta: JSON.stringify(dados, null, 2),
    descricao_problema: item.descricao_problema || "",

    campos_criticos_faltantes: faltantesCriticos.length
      ? faltantesCriticos.join("\n")
      : "Nenhum — os dados essenciais já foram coletados.",

    documentos_recebidos: documentosRecebidos.length ? documentosRecebidos.join(", ") : "Nenhum documento recebido ainda.",
    documentos_faltantes: documentosFaltantes.length ? documentosFaltantes.join(", ") : "Nenhum — todos os documentos já foram recebidos.",
  },
}];

